import{_ as i,o as e,c as a,a3 as o}from"./chunks/framework.LBeL10WQ.js";const g=JSON.parse('{"title":"Onboarding & Operations","description":"","frontmatter":{"title":"Onboarding & Operations"},"headers":[],"relativePath":"en/publishers/onboarding-process.md","filePath":"en/publishers/onboarding-process.md"}'),s={name:"en/publishers/onboarding-process.md"};function n(r,t,l,d,c,p){return e(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="onboarding-and-operations" tabindex="-1">Onboarding and Operations <a class="header-anchor" href="#onboarding-and-operations" aria-label="Permalink to &quot;Onboarding and Operations&quot;">​</a></h1><p>Welcome to getinside! Don&#39;t just wait for campaigns: take control of your ad network, activate your historical partners, and maximize your revenue.</p><h2 id="phase-1-configuration-and-activation" tabindex="-1">Phase 1: Configuration and Activation <a class="header-anchor" href="#phase-1-configuration-and-activation" aria-label="Permalink to &quot;Phase 1: Configuration and Activation&quot;">​</a></h2><div class="gi-step"><div class="gi-step-num">1</div><div class="gi-step-body"><h3>Demo &amp; Account Creation</h3><p>Everything starts with a demo call with the getinside team.</p><ul><li>The team creates your e-retailer account.</li><li>All provided contacts receive an invitation email.</li><li><strong>Action:</strong> Click the link in the email to set your password and access the platform.</li></ul></div></div><div class="gi-step"><div class="gi-step-num">2</div><div class="gi-step-body"><h3>Logistics Configuration</h3><p>Before creating your audiences, define your logistics constraints (essential for the algorithm).</p><ul><li><strong>📍 Warehouse Address</strong> — Delivery location for physical materials (flyers, samples).</li><li><strong>⏱️ Lead Time (Ingestion Delay)</strong> — Incompressible time between receiving pallets and starting insertion. Automatically taken into account by the algorithm to synchronize deliveries.</li></ul></div></div><div class="gi-step"><div class="gi-step-num">3</div><div class="gi-step-body"><h3>Creating Audiences</h3><p>In the <strong>Monetization</strong> tab, create your audience profiles: average order value, B2B/B2C typology, persona profile, visuals (logo, banner). A complete profile improves your <strong>Distributor Score</strong> (out of 5 stars) and your visibility on the marketplace.</p><a href="audience-setup" class="btn btn-outline">Detailed Guide — Audience Profile &amp; Score →</a></div></div><div class="gi-step"><div class="gi-step-num">4</div><div class="gi-step-body"><h3>Adding Campaign Types</h3><p>For each audience created, add the accepted campaign types and their criteria:</p><ul><li><strong>📦 Parcel Insert:</strong> Capacity (max simultaneous flyers), accepted formats, projected weekly volumes over 12 months.</li><li><strong>📧 Digital:</strong> Indicative CPM, examples of past campaigns, performance info (Open Rates, Clicks).</li></ul></div></div><div class="gi-step"><div class="gi-step-num">5</div><div class="gi-step-body"><h3>Validation (Checkout Call)</h3><p>As soon as you feel you have completed the info, notify the getinside team.</p><ul><li>We offer a call to confirm that all necessary information is filled out.</li><li>Review of technical aspects and best practices.</li></ul></div></div><div class="gi-step"><div class="gi-step-num done">✓</div><div class="gi-step-body"><h3>Activation</h3><p>Following the call:</p><ul><li>✅ Validated audiences and campaign types are <strong>activated</strong>.</li><li>⏸️ Incomplete ones remain unlisted in the meantime.</li></ul></div></div><h2 id="phase-2-campaign-management" tabindex="-1">Phase 2: Campaign Management <a class="header-anchor" href="#phase-2-campaign-management" aria-label="Permalink to &quot;Phase 2: Campaign Management&quot;">​</a></h2><div class="gi-step"><div class="gi-step-num">7</div><div class="gi-step-body"><h3>Marketplace Visibility</h3><p>Once activated, advertisers can see your audiences on the platform and start offering you campaigns.</p></div></div><div class="gi-step"><div class="gi-step-num">8</div><div class="gi-step-body"><h3>Reception &amp; Negotiation</h3><p>When a campaign is proposed, all your users receive a notification.</p><p><strong>⏱️ 48-Hour Rule (Critical)</strong> — Respond to any proposal within <strong>48 business hours</strong>. Silence means tacit refusal and incurs a penalty equal to the lost commission.</p><p><strong>Do not refuse, negotiate!</strong> The goal is to fill your inventory:</p><ul><li><strong>💰 Price too low?</strong> Make a counter-proposal on price.</li><li><strong>📅 Dates unavailable?</strong> Suggest another broadcast period.</li><li><strong>📦 Unsuitable volume?</strong> Adjust the proposed quantity.</li></ul><p><strong>💬 Integrated Messaging:</strong> Use the chat to discuss with the advertiser, justify your price, or ask for clarifications.</p></div></div><div class="gi-step"><div class="gi-step-num done">9</div><div class="gi-step-body"><h3>Operational Validation</h3><p>Once the campaign is validated by both parties, we move forward on operations:</p><ul><li><strong>Parcel Insert:</strong> Shipping of materials (respecting lead time).</li><li><strong>Digital:</strong> Transmission of creative assets and integration.</li></ul></div></div><h2 id="phase-3-acceleration-autonomy" tabindex="-1">Phase 3: Acceleration &amp; Autonomy <a class="header-anchor" href="#phase-3-acceleration-autonomy" aria-label="Permalink to &quot;Phase 3: Acceleration &amp; Autonomy&quot;">​</a></h2><div class="gi-step"><div class="gi-step-num">🚀</div><div class="gi-step-body"><h3>Trade Marketing (Your Brands)</h3><p>Do not depend solely on external advertisers. Be proactive with your own suppliers!</p><div class="gi-accent-box"><strong>The concept:</strong> Invite the brands you distribute to buy visibility with you (Parcel Insert, Email, Social) via getinside. <ul><li>✅ <strong>Simplification:</strong> Centralize all management and billing in one place.</li><li>✅ <strong>Profitability:</strong> Generate additional revenue from already acquired partners — <strong>0% network fee</strong> with Platform or Managed offers.</li></ul></div></div></div><div class="gi-step"><div class="gi-step-num">🤝</div><div class="gi-step-body"><h3>Affiliation &amp; Sponsorship</h3><p>Do you know other brands or e-retailers?</p><ul><li>Invite them to join the platform.</li><li>Earn a commission on their activity.</li><li><a href="affiliation">See the affiliation program</a>.</li></ul></div></div><h2 id="contractual-conditions-penalties" tabindex="-1">Contractual Conditions &amp; Penalties <a class="header-anchor" href="#contractual-conditions-penalties" aria-label="Permalink to &quot;Contractual Conditions &amp; Penalties&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Operational Compliance Rules</p><p>In order to maintain a quality service for all our partners, the following conditions apply.</p></div><h3 id="response-time-48-hour-rule" tabindex="-1">Response Time (48-Hour Rule) <a class="header-anchor" href="#response-time-48-hour-rule" aria-label="Permalink to &quot;Response Time (48-Hour Rule)&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">Strict rule: 48 business hours</p><p>You must respond to <strong>any campaign proposal in less than 48 business hours</strong>.</p><p>After this period, lack of response = tacit refusal and incurs a <strong>penalty equivalent to the commission</strong> we would have received on the campaign.</p></div><h3 id="contractual-penalties" tabindex="-1">Contractual Penalties <a class="header-anchor" href="#contractual-penalties" aria-label="Permalink to &quot;Contractual Penalties&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Situation</th><th>Amount</th><th>Detail</th></tr></thead><tbody><tr><td>Cancellation after Validation</td><td><strong>550€ HT</strong></td><td>Flat fee + loss of commission</td></tr><tr><td>Early Contract Termination</td><td><strong>1,550€ HT</strong></td><td>Penalty for unfulfilled annual commitment</td></tr><tr><td>Platform Circumvention</td><td><strong>2,500€ HT / campaign</strong></td><td>Direct Advertiser ↔ Distributor contact outside the platform</td></tr></tbody></table><h3 id="data-protection-gdpr-first-party-data" tabindex="-1">Data Protection (GDPR &amp; First Party Data) <a class="header-anchor" href="#data-protection-gdpr-first-party-data" aria-label="Permalink to &quot;Data Protection (GDPR &amp; First Party Data)&quot;">​</a></h3><div class="tip custom-block"><p class="custom-block-title">TIP</p><p><strong>🛡️ The data is exclusively yours</strong></p><p>getinside acts as a <strong>Trusted Third Party</strong>. No transfer of customer files to an Advertiser is allowed without a specific new GDPR Opt-in.</p><ul><li>You retain ownership of your customer data.</li><li>Advertisers only receive opt-in leads (contests only).</li><li>Any request for additional data requires legal validation.</li></ul></div><h3 id="distributor-veto-right" tabindex="-1">Distributor Veto Right <a class="header-anchor" href="#distributor-veto-right" aria-label="Permalink to &quot;Distributor Veto Right&quot;">​</a></h3><div class="gi-value-grid"><div class="gi-value-card"><strong>✅ You Can Refuse</strong><ul><li><strong>The BRAND:</strong> Ethical or competition reasons.</li><li><strong>Legality:</strong> If the content violates laws.</li><li><strong>Brand Image:</strong> If the campaign contradicts your values.</li></ul></div><div class="gi-value-card"><strong>❌ You Cannot Refuse</strong><ul><li><strong>Art direction:</strong> If the visual respects technical specifications.</li><li><strong>Subjective preferences:</strong> &quot;I don&#39;t find it pretty&quot; is not a valid reason.</li><li><strong>Commercial reasons alone:</strong> Price too low → Negotiate rather than refuse.</li></ul></div></div>',26)])])}const h=i(s,[["render",n]]);export{g as __pageData,h as default};
